const zone = 'America/New_York';
const slotMin = 30;
const dayStart = 10;
const dayEnd = 17;
const maxSuggestions = 4;

const busy = items
  .map(i => i.json)
  .filter(e => e && e.start && (e.start.dateTime || e.start.date))
  .map(e => ({
    start: DateTime.fromISO(e.start.dateTime || e.start.date, { zone }),
    end: DateTime.fromISO((e.end && (e.end.dateTime || e.end.date)) || e.start.dateTime || e.start.date, { zone }),
  }));

const now = DateTime.now().setZone(zone);
const day0 = now.startOf('day');
const slots = [];

for (let d = 0; d < 14 && slots.length < maxSuggestions; d++) {
  const cur = day0.plus({ days: d });
  if (cur.weekday > 5) continue;
  let found = null;
  for (let h = dayStart; h < dayEnd && !found; h++) {
    for (let m = 0; m < 60 && !found; m += slotMin) {
      const s = cur.set({ hour: h, minute: m, second: 0, millisecond: 0 });
      const e = s.plus({ minutes: slotMin });
      if (s <= now) continue;
      const overlap = busy.some(b => s < b.end && e > b.start);
      if (!overlap) found = { iso: s.toISO(), label: s.toFormat("cccc LLLL d 'at' h:mm a") };
    }
  }
  if (found) slots.push(found);
}

return [{ json: { slots } }];
